    "Frequency Shifter",
    "Digital Delay",
    "Tape Delay",
    "Ping Pong",
    "Tape Loop",
    "Plate Reverb",
    "Spring Reverb",
    "Freeverb",
    "Shimmer Reverb",
    "Cathedral Reverb",
    "Granular Clouds",
    "Micro Looper",
    "Tape Degradation",
    "Lossy Audio",
    "Spectral Freeze",
    "Basic Reverb",
    "Allpass Reverb",
    "Hadamard Reverb",
    "Oil-Can Echo",
    "Resonator",
    "Wind",
    "Chatter",
    # Synth Modes (indices 32-44, must match main.cpp voice indices)
    "Wavetable",       # 32
    "Virtual Analog",  # 33 (formerly VA Bass — rewritten as Lead/Bass)
    "Strings",         # 34
    "Piano",           # 35
    "Modal",           # 36
