def generate_tts_wav(text, filename):
    # macOS 'say' command
    # --data-format=LEI16@22050 : Linear PCM 16-bit 22.05kHz (Good for ADPCM)
    
    cmd = [
        "say",
        "-v", "Samantha", # "Samantha" is decent. "Daniel" is British. 
        "--data-format=LEI16@24000",
        "-o", filename,
        text
    ]
    subprocess.run(cmd, check=True)

def main():
    print("Generating TTS Assets...")
    
    header_path = "../lib/pipicofx/inc/voice_data.h"
    wav_files = []
    
    # 1. Generate WAVs
    if not os.path.exists("assets_tmp"):
        os.makedirs("assets_tmp")
        
    for i, name in enumerate(EFFECTS):
        clean_name = f"{i:02d}_{name.replace(' ', '_').upper()}"
        filename = f"assets_tmp/{clean_name}.wav"
        print(f"Generating: '{name}' -> {filename}")
        
        generate_tts_wav(name, filename)
             
        wav_files.append((filename, i)) # Store index for array ordering
        
    # 2. Convert to Header
    print(f"Encoding to {header_path}...")
    
    with open(header_path, "w") as f:
        f.write("#ifndef VOICE_DATA_H\n")
        f.write("#define VOICE_DATA_H\n")
        f.write("// Auto-generated by generate_assets.py\n\n")
        
        registry = []
        
        for filename, idx in wav_files:
            try:
                w = wave.open(filename, 'rb')
                if w.getnchannels() != 1:
                    print(f"Converting Stereo to Mono: {filename}")
                    # Could use ffmpeg, but 'say' output is usually mono?
                    # actually 'say' might output stereo.
                    # If stereo, we need to mixdown.
                    # For simplicity, let's assume 'say' produces understandable mono or check channel.
                    pass 
                
                frames = w.readframes(w.getnframes())
                # Assume 16-bit
                raw_samples = struct.unpack(f"<{len(frames)//2}h", frames)
                
                # Take left channel if stereo (interleaved L, R)
                n_ch = w.getnchannels()
                if n_ch > 1:
                    mono_samples = raw_samples[0::n_ch]
                else:
                    mono_samples = raw_samples
                
                # Encode
                data = wav2header.encode_adpcm(mono_samples)
                
                # Write Array
                var_name = f"DATA_FX_{idx}"
                f.write(f"static const uint8_t {var_name}[] = {{")
                for k, b in enumerate(data):
                    if k % 12 == 0: f.write("\n    ")
                    f.write(f"0x{b:02X}, ")
                f.write("\n};\n\n")
                
                registry.append((var_name, len(mono_samples)))
                
                w.close()
                
            except Exception as e:
                print(f"Error {filename}: {e}")
        
        # Write Accessor Table
        f.write("static const uint8_t* const VOICE_DATA_PTRS[] = {\n")
        for var_name, _ in registry:
            f.write(f"    {var_name},\n")
        f.write("};\n\n")
        
        f.write("static const uint32_t VOICE_DATA_LENS[] = {\n")
        for _, length in registry:
            f.write(f"    {length},\n")
        f.write("};\n\n")
        
        # Getter Functions
        f.write("static inline const uint8_t* getVoiceData(int index) {\n")
        f.write(f"    if (index < 0 || index >= {len(registry)}) return 0;\n")
        f.write("    return VOICE_DATA_PTRS[index];\n")
        f.write("}\n\n")
        
        f.write("static inline uint32_t getVoiceLen(int index) {\n")
        f.write(f"    if (index < 0 || index >= {len(registry)}) return 0;\n")
        f.write("    return VOICE_DATA_LENS[index];\n")
        f.write("}\n")
        
        f.write("#endif\n")
        
    print("Done! Run 'make' to recompile.")

if __name__ == "__main__":
    main()
